sequence.script:
var isEmpty = false;
try {
    var req = mc.getPayloadJSON();
    if (req === null || (typeof req === "object" && Object.keys(req).length === 0)) {
        isEmpty = true;
    }
} catch (e) {
    isEmpty = true;
}
mc.setProperty("IS_EMPTY_BODY", isEmpty ? "true" : "false");

then.script:
try {
    var p = mc.getPayloadJSON();
    mc.setProperty("policyResponse", JSON.stringify(p));
    var ok = p && p.policyNumber;
    mc.setProperty("POLICY_FETCH_OK", ok ? "true" : "false");
} catch (e) {
    mc.setProperty("policyResponse", "{}");
    mc.setProperty("POLICY_FETCH_OK", "false");
}

sequence.script:
var req = mc.getPayloadJSON();
var policyStr = mc.getProperty("policyResponse");
var policy = policyStr ? JSON.parse(policyStr) : {};

function arr(x){ return Array.isArray(x) ? x : []; }
function exists(x){ return x !== undefined && x !== null; }

function shallowCopy(obj){
    var o = {};
    if (!obj) return o;
    for (var k in obj) {
        if (Object.prototype.hasOwnProperty.call(obj, k)) {
            o[k] = obj[k];
        }
    }
    return o;
}

function nextDriverStart(pol){
    var maxN = 0;
    arr(pol.driverDetails).forEach(function(d){
        var m = String(d.driverIdentifier || "").match(/DR-(\d+)/);
        if (m) maxN = Math.max(maxN, parseInt(m[1], 10));
    });
    return maxN;
}

function nextVehStart(pol){
    var maxN = 0;
    arr(pol.insurableObjects).forEach(function(io){
        var m = String(io.insurableObjectIdentifier || "").match(/VEH-(\d+)/);
        if (m) maxN = Math.max(maxN, parseInt(m[1], 10));
    });
    return maxN;
}

function normalizeCoveragesForUpdate(covObj, ioId){
    covObj = covObj || {};
    var addArr = arr(covObj.add || covObj.added);
    var updArr = arr(covObj.update || covObj.updated);
    var remArr = arr(covObj.remove || covObj.removed);

    var addedArr = addArr.map(function(c, idx){
        var out = shallowCopy(c);
        if (!out.coverageIdentifier) {
            out.coverageIdentifier = "COV-VEH-" + (idx + 1) + "-" + ioId;
        }
        return out;
    });

    return {
        added: addedArr,
        updated: updArr,
        removed: remArr
    };
}

function normalizeFieldValuesForUpdate(fieldValues, ioId){
    fieldValues = fieldValues || {};
    var out = shallowCopy(fieldValues);

    if (out.coverages) {
        out.coverages = normalizeCoveragesForUpdate(out.coverages, ioId);
    }
    return out;
}

var driverBase = nextDriverStart(policy);
var ioBase = nextVehStart(policy);
var pv = policy.policyVersion || {};
var endorsementId = "EID" + new Date().getTime();

var changes = req.changes || {};
var dc = changes.driverChanges || changes.drivers || {};
var addDrivers = arr(dc.add || dc.added);
var updDrivers = arr(dc.update || dc.updated);
var remDrivers = arr(dc.remove || dc.removed);

var driversAdded = addDrivers.map(function(d, i){
    return {
        driverIdentifier: "DR-" + (driverBase + i + 1),
        driverName: d.driverName,
        driverLicenseNumber: d.driverLicenseNumber,
        driverLicenseJurisdictionCode: d.driverLicenseJurisdictionCode,
        driverLicenseJurisdictionZipCode: d.driverLicenseJurisdictionZipCode,
        drivingExperienceYearCount: d.drivingExperienceYearCount,
        yearsLicensedCount: d.yearsLicensedCount,
        accidentCount: d.accidentCount,
        violationCount: d.violationCount
    };
});

var driversUpdated = updDrivers.map(function(d){
    return {
        driverIdentifier: d.driverIdentifier,
        fieldValues: (d.fieldValues || {})
    };
});

var driversRemoved = remDrivers.map(function(d){
    return { driverIdentifier: d.driverIdentifier };
});

var ioc = changes.insurableObjectChanges || changes.insurableObjects || {};
var addIO = arr(ioc.add || ioc.added);
var updIO = arr(ioc.update || ioc.updated);
var remIO = arr(ioc.remove || ioc.removed);

var insurableObjectsAdded = addIO.map(function(io, i){
    var vehSeq = ioBase + i + 1;
    var ioId = "VEH-" + vehSeq;

    return {
        insurableObjectIdentifier: ioId,
        insurableObjectTypeCode: io.insurableObjectTypeCode,
        vehicle: io.vehicle || {},
        coverages: arr(io.coverages).map(function(cov, idx){
            return {
                insurableObjectIdentifier: ioId,
                coverageIdentifier: "COV-VEH-" + (idx + 1) + "-" + vehSeq,
                coverageName: cov.coverageName,
                limits: arr(cov.limits),
                deductibles: arr(cov.deductibles)
            };
        })
    };
});

var insurableObjectsUpdated = updIO.map(function(io){
    return {
        insurableObjectIdentifier: io.insurableObjectIdentifier,
        fieldValues: normalizeFieldValuesForUpdate(io.fieldValues || {}, io.insurableObjectIdentifier)
    };
});

var insurableObjectsRemoved = remIO.map(function(io){
    return { insurableObjectIdentifier: io.insurableObjectIdentifier };
});

var endorsementResponse = {
    policyNumber: req.policyNumber || mc.getProperty("policyId"),
    endorsementId: endorsementId,
    endorsementStatusCode: "PENDING",
    productCode: req.productCode,
    endorsementName: req.endorsementName,
    endorsementCategory: req.endorsementCategory,
    endorsementState: req.endorsementState,
    endorsementEffectiveDate: req.endorsementEffectiveDate,
    transactionDate: req.transactionDate,
    policyEvent: {
        eventTypeCode: req.policyEvent && req.policyEvent.eventTypeCode,
        eventDate: req.policyEvent && req.policyEvent.eventDate
    },
    policyVersion: {
        policyVersionIdentifier: exists(pv.policyVersionIdentifier) ? pv.policyVersionIdentifier : "PV-001",
        versionNumber: exists(pv.versionNumber) ? pv.versionNumber : 1,
        transactionTypeCode: (req.policyEvent && req.policyEvent.eventTypeCode) || "ENDORSEMENT",
        versionEffectiveDate: req.endorsementEffectiveDate
    },
    reprice: req.reprice,
    conflictHandling: req.conflictHandling,
    changes: {
        drivers: { added: driversAdded, updated: driversUpdated, removed: driversRemoved },
        insurableObjects: { added: insurableObjectsAdded, updated: insurableObjectsUpdated, removed: insurableObjectsRemoved }
    },
    message: "Endorsement application created successfully"
};

mc.setProperty("endorsementResponseObj", JSON.stringify(endorsementResponse));
mc.setProperty("endorsementId", endorsementId);
